// src/BusMap.jsx
import React, { useEffect, useState, useRef } from "react";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

// Custom icons
const runningIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/1048/1048313.png",
  iconSize: [32, 32],
});
const ghostIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/4667/4667700.png",
  iconSize: [32, 32],
});
const anomalyIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/671/671497.png",
  iconSize: [32, 32],
});

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [filters, setFilters] = useState({
    running: true,
    ghost: true,
    anomaly: true,
  });

  const ws = useRef(null);

  useEffect(() => {
    // Connect WebSocket
    ws.current = new WebSocket("ws://localhost:8000/ws/buses");

    ws.current.onmessage = (event) => {
      const data = JSON.parse(event.data);
      const busesArray = Object.values(data);

      setBuses(busesArray);

      // Alerts for ghost/anomaly
      busesArray.forEach((bus) => {
        if (bus.status === "Ghost") {
          alert(`⚠️ Ghost Bus Detected! Bus ID: ${bus.id}, Route: ${bus.route}`);
        } else if (bus.status.includes("Anomaly")) {
          alert(`🚨 Anomaly Detected! Bus ID: ${bus.id}, Status: ${bus.status}`);
        }
      });
    };

    ws.current.onclose = () => {
      console.log("WebSocket closed, retrying...");
      setTimeout(() => {
        ws.current = new WebSocket("ws://localhost:8000/ws/buses");
      }, 2000);
    };

    return () => {
      ws.current.close();
    };
  }, []);

  // Filter buses based on toggle
  const filteredBuses = buses.filter((bus) => {
    if (bus.status === "Running" && !filters.running) return false;
    if (bus.status === "Ghost" && !filters.ghost) return false;
    if (bus.status.includes("Anomaly") && !filters.anomaly) return false;
    return true;
  });

  return (
    <div style={{ height: "100vh", width: "100%" }}>
      {/* Filter Buttons */}
      <div style={{ padding: "10px", background: "#f0f0f0" }}>
        <button onClick={() => setFilters({ ...filters, running: !filters.running })}>
          {filters.running ? "Hide Running" : "Show Running"}
        </button>
        <button onClick={() => setFilters({ ...filters, ghost: !filters.ghost })}>
          {filters.ghost ? "Hide Ghosts" : "Show Ghosts"}
        </button>
        <button onClick={() => setFilters({ ...filters, anomaly: !filters.anomaly })}>
          {filters.anomaly ? "Hide Anomalies" : "Show Anomalies"}
        </button>
      </div>

      {/* Map */}
      <MapContainer center={[40.7128, -74.006]} zoom={12} style={{ height: "90%", width: "100%" }}>
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution="© OpenStreetMap contributors"
        />

        {filteredBuses.map((bus) => {
          let icon = runningIcon;
          if (bus.status === "Ghost") icon = ghostIcon;
          else if (bus.status.includes("Anomaly")) icon = anomalyIcon;

          return (
            <Marker key={bus.id} position={[bus.lat, bus.lon]} icon={icon}>
              <Popup>
                <b>Bus ID:</b> {bus.id} <br />
                <b>Route:</b> {bus.route} <br />
                <b>Speed:</b> {bus.speed.toFixed(2)} mph <br />
                <b>Status:</b> {bus.status}
              </Popup>
            </Marker>
          );
        })}
      </MapContainer>
    </div>
  );
}
